<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f9; color: #333; padding: 20px; max-width: 900px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.8rem; color: #2c3e50; }
  h2 { font-size: 1.2rem; margin-bottom: 12px; color: #34495e; }

  /* Form */
  .form-section { background: #fff; border-radius: 8px; padding: 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.1); }
  .form-row { display: flex; flex-wrap: wrap; gap: 12px; align-items: flex-end; margin-bottom: 12px; }
  .form-group { display: flex; flex-direction: column; flex: 1; min-width: 120px; }
  .form-group label { font-size: 0.85rem; font-weight: 600; margin-bottom: 4px; color: #555; }
  .form-group input, .form-group select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 4px; font-size: 0.95rem; }
  .form-group input:focus, .form-group select:focus { outline: none; border-color: #3498db; box-shadow: 0 0 0 2px rgba(52,152,219,0.2); }
  #add-expense { padding: 8px 20px; background: #27ae60; color: #fff; border: none; border-radius: 4px; font-size: 0.95rem; cursor: pointer; font-weight: 600; white-space: nowrap; height: 38px; }
  #add-expense:hover { background: #219a52; }
  #form-error { color: #e74c3c; font-size: 0.9rem; min-height: 1.2em; font-weight: 500; }

  /* Filters */
  .filter-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.1); }
  .filter-row { display: flex; flex-wrap: wrap; gap: 12px; align-items: flex-end; }
  .filter-group { display: flex; flex-direction: column; min-width: 130px; }
  .filter-group label { font-size: 0.8rem; font-weight: 600; margin-bottom: 4px; color: #555; }
  .filter-group select, .filter-group input { padding: 6px 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 0.9rem; }
  .filter-group select:focus, .filter-group input:focus { outline: none; border-color: #3498db; }

  /* Summary */
  .summary-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.1); }
  .total-display { font-size: 1.4rem; font-weight: 700; color: #2c3e50; margin-bottom: 12px; }
  .total-display span { color: #27ae60; }
  .cat-totals { display: flex; flex-wrap: wrap; gap: 12px; }
  .cat-total { background: #f0f4f8; border-radius: 6px; padding: 8px 16px; font-size: 0.9rem; min-width: 120px; }
  .cat-total strong { color: #2c3e50; }
  .cat-total .cat-amount { color: #2980b9; font-weight: 600; }

  /* Expense list */
  .list-section { background: #fff; border-radius: 8px; padding: 16px 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.1); }
  .expense-table { width: 100%; border-collapse: collapse; }
  .expense-table th { text-align: left; padding: 8px 10px; font-size: 0.8rem; text-transform: uppercase; color: #7f8c8d; border-bottom: 2px solid #ecf0f1; }
  .expense-table td { padding: 10px; border-bottom: 1px solid #ecf0f1; font-size: 0.95rem; }
  .expense-table tr.expense:hover { background: #f9fbfd; }
  .expense-table .exp-amount { font-weight: 600; color: #c0392b; }
  .expense-table .exp-category { color: #2980b9; }
  .expense-table .exp-date { color: #7f8c8d; }
  .expense-table .exp-note { color: #95a5a6; font-style: italic; max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .exp-del { background: #e74c3c; color: #fff; border: none; border-radius: 4px; padding: 4px 10px; cursor: pointer; font-size: 0.8rem; font-weight: 600; }
  .exp-del:hover { background: #c0392b; }
  .no-expenses { text-align: center; padding: 30px; color: #95a5a6; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="form-section">
  <h2>Add Expense</h2>
  <div class="form-row">
    <div class="form-group" style="flex:0.8;min-width:100px;">
      <label for="amount">Amount</label>
      <input type="number" id="amount" min="0" step="0.01" placeholder="0.00">
    </div>
    <div class="form-group" style="flex:1;min-width:130px;">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group" style="flex:0.8;min-width:130px;">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group" style="flex:1.5;min-width:180px;">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shopping">
    </div>
  </div>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filter-section">
  <h2>Filters</h2>
  <div class="filter-row">
    <div class="filter-group">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="filter-group">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="filter-group">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<!-- Summary -->
<div class="summary-section">
  <h2>Summary</h2>
  <div class="total-display">Total: <span id="total">0.00</span></div>
  <div class="cat-totals" id="cat-totals"></div>
</div>

<!-- Expense List -->
<div class="list-section">
  <h2>Expenses</h2>
  <table class="expense-table">
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
</div>

<script>
(function() {
  const STORAGE_KEY = 'expense-tracker-data';
  const categories = ['groceries', 'transport', 'bills', 'fun'];

  // DOM refs
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const addBtn = document.getElementById('add-expense');
  const formError = document.getElementById('form-error');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');
  const totalEl = document.getElementById('total');
  const catTotalsEl = document.getElementById('cat-totals');
  const expenseListEl = document.getElementById('expense-list');

  // State
  let expenses = [];

  // Load from localStorage
  function loadExpenses() {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) {
        expenses = JSON.parse(data);
      }
    } catch(e) {
      expenses = [];
    }
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Generate unique ID
  function generateId() {
    return Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
  }

  // Format number to 2 decimals
  function formatAmount(num) {
    return num.toFixed(2);
  }

  // Validate form
  function validateForm() {
    const rawAmount = amountInput.value.trim();
    const dateVal = dateInput.value.trim();

    if (rawAmount === '' || isNaN(Number(rawAmount)) || Number(rawAmount) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return false;
    }
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return false;
    }
    formError.textContent = '';
    return true;
  }

  // Add expense
  function addExpense() {
    if (!validateForm()) return;

    const amount = parseFloat(amountInput.value);
    const category = categorySelect.value;
    const date = dateInput.value;
    const note = noteInput.value.trim();

    const expense = {
      id: generateId(),
      amount: amount,
      category: category,
      date: date,
      note: note,
      createdAt: Date.now()
    };

    expenses.push(expense);
    saveExpenses();

    // Clear amount and error
    amountInput.value = '';
    formError.textContent = '';

    render();
  }

  // Delete expense
  function deleteExpense(id) {
    expenses = expenses.filter(function(e) { return e.id !== id; });
    saveExpenses();
    render();
  }

  // Get filtered expenses (newest first)
  function getFilteredExpenses() {
    let filtered = expenses.slice();

    // Category filter
    const catFilter = filterCategory.value;
    if (catFilter !== 'all') {
      filtered = filtered.filter(function(e) { return e.category === catFilter; });
    }

    // Date range filter
    const fromVal = filterFrom.value;
    const toVal = filterTo.value;
    if (fromVal) {
      filtered = filtered.filter(function(e) { return e.date >= fromVal; });
    }
    if (toVal) {
      filtered = filtered.filter(function(e) { return e.date <= toVal; });
    }

    // Sort newest first (by createdAt descending, then by date descending as tiebreaker)
    filtered.sort(function(a, b) {
      if (b.createdAt !== a.createdAt) return b.createdAt - a.createdAt;
      return b.date.localeCompare(a.date);
    });

    return filtered;
  }

  // Render expense list
  function renderList(filtered) {
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<tr><td colspan="5" class="no-expenses">No expenses to display.</td></tr>';
      return;
    }

    let html = '';
    filtered.forEach(function(exp) {
      html += '<tr class="expense" data-id="' + exp.id + '">' +
        '<td class="exp-amount">' + formatAmount(exp.amount) + '</td>' +
        '<td class="exp-category">' + exp.category + '</td>' +
        '<td class="exp-date">' + exp.date + '</td>' +
        '<td class="exp-note">' + (exp.note ? escapeHtml(exp.note) : '') + '</td>' +
        '<td><button class="exp-del" data-id="' + exp.id + '">Delete</button></td>' +
        '</tr>';
    });
    expenseListEl.innerHTML = html;
  }

  // Escape HTML
  function escapeHtml(str) {
    var div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
  }

  // Render summary
  function renderSummary(filtered) {
    // Total
    var total = 0;
    var catSums = {};
    categories.forEach(function(c) { catSums[c] = 0; });

    filtered.forEach(function(exp) {
      total += exp.amount;
      if (catSums.hasOwnProperty(exp.category)) {
        catSums[exp.category] += exp.amount;
      }
    });

    totalEl.textContent = formatAmount(total);

    // Per-category totals
    let catHtml = '';
    categories.forEach(function(cat) {
      catHtml += '<div class="cat-total" data-cat="' + cat + '">' +
        '<strong>' + cat + ':</strong> ' +
        '<span class="cat-amount">' + formatAmount(catSums[cat]) + '</span>' +
        '</div>';
    });
    catTotalsEl.innerHTML = catHtml;
  }

  // Full render
  function render() {
    var filtered = getFilteredExpenses();
    renderList(filtered);
    renderSummary(filtered);
  }

  // Event listeners
  addBtn.addEventListener('click', addExpense);

  // Allow Enter key in amount field to submit
  amountInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      e.preventDefault();
      addExpense();
    }
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // Delegate delete clicks
  expenseListEl.addEventListener('click', function(e) {
    var btn = e.target;
    if (btn.classList.contains('exp-del')) {
      var id = btn.getAttribute('data-id');
      deleteExpense(id);
    }
  });

  // Set default date to today
  function setToday() {
    var d = new Date();
    var yyyy = d.getFullYear();
    var mm = String(d.getMonth() + 1).padStart(2, '0');
    var dd = String(d.getDate()).padStart(2, '0');
    dateInput.value = yyyy + '-' + mm + '-' + dd;
  }

  // Initialize
  loadExpenses();
  setToday();
  render();
})();
</script>

</body>
</html>
